/**
 * Ernest Logger v2.0.0 TypeScript Definitions
 */

export type LogLevel = 'trace' | 'debug' | 'info' | 'success' | 'warn' | 'error' | 'fatal';

export type ColorName = 
  | 'black' | 'red' | 'green' | 'yellow' | 'blue' | 'magenta' | 'cyan' | 'white'
  | 'brightBlack' | 'brightRed' | 'brightGreen' | 'brightYellow' 
  | 'brightBlue' | 'brightMagenta' | 'brightCyan' | 'brightWhite'
  | 'dim';

export interface CustomLevel {
  color: ColorName;
  emoji: string;
  priority?: number;
}

export interface LoggerOptions {
  /**
   * Enable/disable timestamp in logs (default: true)
   */
  time?: boolean;

  /**
   * Enable/disable emojis in logs (default: true)
   */
  emoji?: boolean;

  /**
   * Minimum log level to display (default: 'debug')
   */
  level?: LogLevel;

  /**
   * Enable file logging (default: false)
   */
  file?: boolean;

  /**
   * Custom log file path (default: './ernest.log')
   */
  filePath?: string;

  /**
   * Enable/disable color output (default: true)
   */
  colorize?: boolean;

  /**
   * Custom prefix for all log messages
   */
  prefix?: string;

  /**
   * Maximum log file size before rotation in bytes (default: 5MB)
   */
  maxFileSize?: number;

  /**
   * Define custom log levels
   */
  customLevels?: Record<string, CustomLevel>;
}

export interface BigLogOptions {
  color?: ColorName;
  emoji?: string;
}

export interface ColoredLogMethods {
  [color: string]: (message: string) => void;
}

export interface NestedLogger {
  trace?: ColoredLogMethods;
  debug?: ColoredLogMethods;
  info?: ColoredLogMethods;
  success?: ColoredLogMethods;
  warn?: ColoredLogMethods;
  error?: ColoredLogMethods;
  fatal?: ColoredLogMethods;
  [customLevel: string]: ColoredLogMethods | undefined;
}

export interface Logger {
  // Quick log methods (with smart defaults)
  trace(message: string): void;
  debug(message: string): void;
  info(message: string): void;
  success(message: string): void;
  warn(message: string): void;
  error(message: string): void;
  fatal(message: string): void;

  // Specialized methods
  start(message: string): void;
  stop(message: string): void;
  network(message: string): void;
  db(message: string): void;
  api(message: string): void;
  security(message: string): void;

  // Advanced logging methods
  bigLog(message: string, options?: BigLogOptions): void;
  table(data: any): void;
  json(obj: any, label?: string): void;

  // Grouping
  group(label: string): void;
  groupEnd(): void;

  // Timing
  time(label: string): void;
  timeEnd(label: string): void;

  // Nested logger with color control
  log: NestedLogger;

  // Configuration methods
  configure(options: Partial<LoggerOptions>): Logger;
  getConfig(): LoggerOptions;

  // Feature toggles
  enableTime(): Logger;
  disableTime(): Logger;
  enableEmoji(): Logger;
  disableEmoji(): Logger;
  enableFile(): Logger;
  disableFile(): Logger;
  setLevel(level: LogLevel): Logger;
}

/**
 * Create a new logger instance with custom configuration
 */
export function createLogger(options?: LoggerOptions): Logger;

/**
 * Set global default configuration for all future logger instances
 */
export function setGlobalConfig(config: Partial<LoggerOptions>): void;

/**
 * Default logger instance (ready to use immediately)
 */
declare const defaultLogger: Logger;

export default defaultLogger;